#!/usr/bin/env python3

import sys
import argparse
import json
from kafka.admin import KafkaAdminClient, NewTopic, ConfigResource, ConfigResourceType
from kafka.errors import TopicAlreadyExistsError, UnknownTopicOrPartitionError, KafkaError


def create_admin_client(bootstrap_servers):
    return KafkaAdminClient(
        bootstrap_servers=bootstrap_servers,
        client_id='kafka-admin-script'
    )


def create_topics(admin_client, topics_config):
    new_topics = []
    for topic_config in topics_config:
        topic_name = topic_config['name']
        num_partitions = topic_config.get('partitions', 1)
        replication_factor = topic_config.get('replication_factor', 1)
        topic_configs = topic_config.get('configs', {})
        
        new_topic = NewTopic(
            name=topic_name,
            num_partitions=num_partitions,
            replication_factor=replication_factor,
            topic_configs=topic_configs
        )
        new_topics.append(new_topic)
    
    try:
        result = admin_client.create_topics(new_topics=new_topics, validate_only=False)
        for topic, future in result.items():
            try:
                future.result()
                print(f"Topic '{topic}' created successfully")
            except TopicAlreadyExistsError:
                print(f"Topic '{topic}' already exists")
            except Exception as e:
                print(f"Failed to create topic '{topic}': {e}")
    except Exception as e:
        print(f"Error creating topics: {e}")


def delete_topics(admin_client, topic_names):
    try:
        result = admin_client.delete_topics(topics=topic_names)
        for topic, future in result.items():
            try:
                future.result()
                print(f"Topic '{topic}' deleted successfully")
            except UnknownTopicOrPartitionError:
                print(f"Topic '{topic}' does not exist")
            except Exception as e:
                print(f"Failed to delete topic '{topic}': {e}")
    except Exception as e:
        print(f"Error deleting topics: {e}")


def list_topics(admin_client):
    try:
        topics = admin_client.list_topics()
        print("Available topics:")
        for topic in sorted(topics):
            print(f"  - {topic}")
    except Exception as e:
        print(f"Error listing topics: {e}")


def describe_topics(admin_client, topic_names):
    try:
        metadata = admin_client._client.cluster
        metadata.request_update()
        
        for topic_name in topic_names:
            topic = metadata.topics().get(topic_name)
            if topic:
                print(f"\nTopic: {topic_name}")
                print(f"  Partitions: {len(topic.partitions)}")
                for partition_id, partition in sorted(topic.partitions.items()):
                    print(f"    Partition {partition_id}:")
                    print(f"      Leader: {partition.leader}")
                    print(f"      Replicas: {partition.replicas}")
                    print(f"      ISR: {partition.isr}")
            else:
                print(f"Topic '{topic_name}' not found")
    except Exception as e:
        print(f"Error describing topics: {e}")


def alter_topic_configs(admin_client, topic_name, configs):
    try:
        config_resource = ConfigResource(
            ConfigResourceType.TOPIC,
            topic_name,
            configs=configs
        )
        
        result = admin_client.alter_configs([config_resource])
        for resource, future in result.items():
            try:
                future.result()
                print(f"Configuration for topic '{topic_name}' updated successfully")
            except Exception as e:
                print(f"Failed to update configuration for topic '{topic_name}': {e}")
    except Exception as e:
        print(f"Error altering topic configs: {e}")


def describe_topic_configs(admin_client, topic_names):
    try:
        config_resources = [
            ConfigResource(ConfigResourceType.TOPIC, topic_name)
            for topic_name in topic_names
        ]
        
        result = admin_client.describe_configs(config_resources)
        for resource, future in result.items():
            try:
                configs = future.result()
                print(f"\nTopic: {resource.name}")
                print("  Configurations:")
                for config_name, config_value in sorted(configs.items()):
                    print(f"    {config_name}: {config_value.value}")
            except Exception as e:
                print(f"Failed to describe configs for topic '{resource.name}': {e}")
    except Exception as e:
        print(f"Error describing topic configs: {e}")


def create_partitions(admin_client, topic_partitions):
    try:
        from kafka.admin import NewPartitions
        
        new_partitions = {}
        for topic_name, total_count in topic_partitions.items():
            new_partitions[topic_name] = NewPartitions(total_count=total_count)
        
        result = admin_client.create_partitions(new_partitions)
        for topic, future in result.items():
            try:
                future.result()
                print(f"Partitions for topic '{topic}' created successfully")
            except Exception as e:
                print(f"Failed to create partitions for topic '{topic}': {e}")
    except Exception as e:
        print(f"Error creating partitions: {e}")


def main():
    parser = argparse.ArgumentParser(description='Kafka Cluster Administration Tool')
    parser.add_argument('--bootstrap-servers', required=True, help='Kafka bootstrap servers (comma-separated)')
    
    subparsers = parser.add_subparsers(dest='command', help='Command to execute')
    
    create_parser = subparsers.add_parser('create', help='Create topics')
    create_parser.add_argument('--topic', required=True, help='Topic name')
    create_parser.add_argument('--partitions', type=int, default=1, help='Number of partitions')
    create_parser.add_argument('--replication-factor', type=int, default=1, help='Replication factor')
    create_parser.add_argument('--config', action='append', help='Topic configuration (key=value)')
    create_parser.add_argument('--config-file', help='JSON file with topic configurations')
    
    delete_parser = subparsers.add_parser('delete', help='Delete topics')
    delete_parser.add_argument('--topics', required=True, nargs='+', help='Topic names to delete')
    
    list_parser = subparsers.add_parser('list', help='List all topics')
    
    describe_parser = subparsers.add_parser('describe', help='Describe topics')
    describe_parser.add_argument('--topics', required=True, nargs='+', help='Topic names to describe')
    
    alter_parser = subparsers.add_parser('alter-config', help='Alter topic configuration')
    alter_parser.add_argument('--topic', required=True, help='Topic name')
    alter_parser.add_argument('--config', required=True, action='append', help='Configuration (key=value)')
    
    describe_config_parser = subparsers.add_parser('describe-config', help='Describe topic configuration')
    describe_config_parser.add_argument('--topics', required=True, nargs='+', help='Topic names')
    
    add_partitions_parser = subparsers.add_parser('add-partitions', help='Add partitions to topic')
    add_partitions_parser.add_argument('--topic', required=True, help='Topic name')
    add_partitions_parser.add_argument('--total-count', required=True, type=int, help='Total partition count')
    
    args = parser.parse_args()
    
    if not args.command:
        parser.print_help()
        sys.exit(1)
    
    bootstrap_servers = args.bootstrap_servers.split(',')
    admin_client = create_admin_client(bootstrap_servers)
    
    try:
        if args.command == 'create':
            if args.config_file:
                with open(args.config_file, 'r') as f:
                    topics_config = json.load(f)
                    if not isinstance(topics_config, list):
                        topics_config = [topics_config]
            else:
                topic_configs = {}
                if args.config:
                    for config in args.config:
                        key, value = config.split('=', 1)
                        topic_configs[key] = value
                
                topics_config = [{
                    'name': args.topic,
                    'partitions': args.partitions,
                    'replication_factor': args.replication_factor,
                    'configs': topic_configs
                }]
            
            create_topics(admin_client, topics_config)
        
        elif args.command == 'delete':
            delete_topics(admin_client, args.topics)
        
        elif args.command == 'list':
            list_topics(admin_client)
        
        elif args.command == 'describe':
            describe_topics(admin_client, args.topics)
        
        elif args.command == 'alter-config':
            configs = {}
            for config in args.config:
                key, value = config.split('=', 1)
                configs[key] = value
            alter_topic_configs(admin_client, args.topic, configs)
        
        elif args.command == 'describe-config':
            describe_topic_configs(admin_client, args.topics)
        
        elif args.command == 'add-partitions':
            create_partitions(admin_client, {args.topic: args.total_count})
    
    finally:
        admin_client.close()


if __name__ == '__main__':
    main()